const payload = $json.body ?? $json;
const action = String(payload.action ?? '').trim().toLowerCase();
const timezone = 'America/Argentina/Buenos_Aires';

function nowDateInTZ(tz) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return fmt.format(new Date()); // YYYY-MM-DD
}

return [
  {
    json: {
      ...payload,
      action,
      timezone,
      request_ts: new Date().toISOString(),
      today_tz: nowDateInTZ(timezone),
    },
  },
];

const input = $json;
const allowedActions = new Set(['alta','search', 'influencers_search', 'consulta', 'extension', 'baja_manual', 'listar_ads', 'run_now', 'history', 'history_alerts', 'pause_ad', 'pause_active', 'status_by_tracking']);

function isValidDateFormat(value) {
  if (typeof value !== 'string') return false;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) return false;
  const [y, m, d] = value.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  return dt.getUTCFullYear() === y && dt.getUTCMonth() === (m - 1) && dt.getUTCDate() === d;
}

function toBool(value, fallback = false) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const normalized = String(value).trim().toLowerCase();
  return ['1', 'true', 'si', 'yes', 'y'].includes(normalized);
}

function normalizeB64(value) {
  const raw = String(value || '').trim().replace(/-/g, '+').replace(/_/g, '/');
  const padding = raw.length % 4;
  return padding ? raw + '='.repeat(4 - padding) : raw;
}

function badRequest(message, details = {}) {
  const err = new Error(message);
  err.name = 'ValidationError';
  err.details = details;
  throw err;
}

if (!allowedActions.has(input.action)) {
  badRequest('`action` invalida. Usar: alta | search | influencers_search | consulta | extension | baja_manual | listar_ads | run_now | history | history_alerts | pause_ad | pause_active | status_by_tracking', { action: input.action });
}

input.actor = String(input.requested_by ?? input.actor ?? 'ops@adskiller').trim();
input.correlation_id = String(input.correlation_id ?? `ak-ui-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);

const normalizedContratoId = String(input.Contrato_ID ?? input.contract_id ?? input.contractId ?? '').trim();
if (normalizedContratoId) {
  input.Contrato_ID = normalizedContratoId;
  input.contract_id = normalizedContratoId;
}

const normalizedAdId = String(input.Ad_ID ?? input.ad_id ?? input.adId ?? '').trim();
if (normalizedAdId) {
  input.Ad_ID = normalizedAdId;
  input.ad_id = normalizedAdId;
}

if (input.action === 'alta') {
  const required = ['Contrato_ID', 'Cliente', 'Regex_Anuncio', 'Fecha_Fin'];
  const missing = required.filter((f) => !String(input[f] ?? '').trim());
  if (missing.length) badRequest('Faltan campos obligatorios para alta', { missing });
  if (!isValidDateFormat(input.Fecha_Fin)) badRequest('Fecha_Fin invalida. Formato requerido: YYYY-MM-DD');
}

if (input.action === 'extension') {
  const required = ['Contrato_ID', 'Nueva_Fecha_Fin'];
  const missing = required.filter((f) => !String(input[f] ?? '').trim());
  if (missing.length) badRequest('Faltan campos obligatorios para extension', { missing });
  if (!isValidDateFormat(input.Nueva_Fecha_Fin)) badRequest('Nueva_Fecha_Fin invalida. Formato requerido: YYYY-MM-DD');
}

if (input.action === 'search') {
  if (!String(input.q ?? '').trim()) badRequest('q es obligatorio para search');
  input.q = String(input.q).trim();
}

if (input.action === 'consulta') {
  const dias = Number(input.dias_proximos ?? 7);
  if (!Number.isInteger(dias) || dias < 1 || dias > 60) badRequest('dias_proximos invalido. Debe ser entero entre 1 y 60');
  input.dias_proximos = dias;
}

if (input.action === 'pause_ad') {
  const missing = [];
  if (!String(input.Contrato_ID ?? '').trim()) missing.push('contract_id');
  if (!String(input.Ad_ID ?? '').trim()) missing.push('ad_id');
  if (missing.length) {
    badRequest('Faltan campos obligatorios para pause_ad', {
      missing,
      accepted_aliases: {
        contract_id: ['Contrato_ID', 'contract_id', 'contractId'],
        ad_id: ['Ad_ID', 'ad_id', 'adId']
      }
    });
  }
}

if (input.action === 'baja_manual' || input.action === 'listar_ads' || input.action === 'pause_active') {
  if (!String(input.Contrato_ID ?? '').trim()) badRequest('Contrato_ID es obligatorio para esta accion');
}

if (input.action === 'status_by_tracking') {
  const trackingId = String(input.tracking_id ?? input.trackingId ?? '').trim();
  if (!trackingId) badRequest('tracking_id es obligatorio para status_by_tracking');
  input.tracking_id = trackingId;
}

if (input.action === 'pause_active') {
  const dryRun = toBool(input.dry_run, true);
  const maxBatchSize = Number(input.max_batch_size ?? input.batch_limit ?? 20);
  if (!Number.isInteger(maxBatchSize) || maxBatchSize < 1 || maxBatchSize > 100) {
    badRequest('max_batch_size invalido. Debe ser entero entre 1 y 100');
  }

  input.dry_run = dryRun;
  input.max_batch_size = maxBatchSize;
  input.batch_limit = maxBatchSize;

  if (dryRun) {
    input.action = 'pause_active_preview';
  } else {
    const confirmToken = String(input.confirm_token ?? '').trim();
    if (!confirmToken) {
      badRequest('confirm_token es obligatorio cuando dry_run=false');
    }

    try {
      const decoded = JSON.parse(Buffer.from(normalizeB64(confirmToken), 'base64').toString('utf8'));
      const tokenContractId = String(decoded.contract_id ?? '').trim();
      const tokenBatchSize = Number(decoded.max_batch_size ?? 0);
      const expiresAt = Number(decoded.expires_at_epoch_ms ?? 0);

      if (!tokenContractId || tokenContractId !== String(input.Contrato_ID).trim()) {
        badRequest('confirm_token no corresponde al Contrato_ID enviado');
      }
      if (!Number.isInteger(tokenBatchSize) || tokenBatchSize !== maxBatchSize) {
        badRequest('confirm_token no corresponde al max_batch_size enviado');
      }
      if (!Number.isFinite(expiresAt) || Date.now() > expiresAt) {
        badRequest('confirm_token vencido');
      }
    } catch (err) {
      badRequest('confirm_token invalido', { reason: String(err?.message ?? err) });
    }

    input.confirm_token = confirmToken;
    input.confirm = true;
  }
}

if (input.action === 'history' || input.action === 'history_alerts') {
  const page = Number(input.page ?? 1);
  const pageSize = Number(input.page_size ?? 25);
  if (!Number.isInteger(page) || page < 1) badRequest('page invalido. Minimo 1');
  if (!Number.isInteger(pageSize) || pageSize < 1 || pageSize > 100) badRequest('page_size invalido. Debe ser 1..100');
  input.page = page;
  input.page_size = pageSize;
}

return [{ json: input }];

return [{
  json: {
    Contrato_ID: String($json.Contrato_ID).trim(),
    Cliente: String($json.Cliente).trim(),
    Regex_Anuncio: String($json.Regex_Anuncio).trim(),
    Fecha_Alta: String($json.Fecha_Alta ?? $json.today_tz),
    Fecha_Fin: String($json.Fecha_Fin),
    Status_Contrato: String($json.Status_Contrato ?? 'Activo'),
    Notificado_Previo: false,
    Ad_ID: String($json.Ad_ID ?? ''),
    Ad_Name: String($json.Ad_Name ?? ''),
    Fecha_Notificado_Previo: '',
    Fecha_Finalizacion: '',
    Updated_At: $json.request_ts,
  },
}];

const trigger = $items('Validate Input', 0, 0)[0].json;
const dias = Number(trigger.dias_proximos ?? 7);

function parseYmd(ymd) {
  const [y, m, d] = String(ymd).split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d));
}

const today = parseYmd(trigger.today_tz);
const maxDate = new Date(today.getTime() + dias * 24 * 60 * 60 * 1000);

const out = [];
for (const item of items) {
  const row = item.json;
  const exp = String(row.Fecha_Fin ?? '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(exp)) continue;

  const expDate = parseYmd(exp);
  if (row.Status_Contrato === 'Finalizado') continue;

  if (expDate >= today && expDate <= maxDate) {
    out.push({ json: row });
  }
}

out.sort((a, b) => String(a.json.Fecha_Fin).localeCompare(String(b.json.Fecha_Fin)));
return out;

const req = $items('Validate Input', 0, 0)[0].json;
const idContrato = String(req.Contrato_ID).trim();
const found = items.find((i) => String(i.json.Contrato_ID ?? '').trim() === idContrato);

if (!found) {
  const err = new Error('Contrato no encontrado para extension');
  err.name = 'NotFoundError';
  err.details = { Contrato_ID: idContrato };
  throw err;
}

return [{
  json: {
    ...found.json,
    Contrato_ID: idContrato,
    Fecha_Fin: String(req.Nueva_Fecha_Fin),
    Notificado_Previo: false,
    Updated_At: req.request_ts,
  },
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();
const safeAction = String(input.action ?? 'unknown').trim().toLowerCase();
const correlationId = String(input.correlation_id ?? `ak-f1-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
const logicalExecutionId = String(input.logical_execution_id ?? `${correlationId}:f1:${safeAction}`);

return [{
  json: {
    schema_version: '1.0.0',
    event_type: 'contract.ui.action',
    source_workflow: 'contract-ui-management-v2',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    timezone: String(input.timezone ?? 'America/Argentina/Buenos_Aires'),
    correlation_id: correlationId,
    logical_execution_id: logicalExecutionId,
    execution: {
      n8n_execution_id: String($execution?.id ?? ''),
      run_type: 'internal_execute_workflow',
      status: 'queued'
    },
    payload: {
      action: safeAction,
      run_mode: String(input.run_mode ?? 'manual'),
      actor: String(input.actor ?? 'ops@adskiller'),
      tracking_id: String(input.tracking_id ?? ''),
      Contrato_ID: String(input.Contrato_ID ?? ''),
      Ad_ID: String(input.Ad_ID ?? ''),
      Fecha_Fin: String(input.Fecha_Fin ?? ''),
      Nueva_Fecha_Fin: String(input.Nueva_Fecha_Fin ?? ''),
      Regex_Anuncio: String(input.Regex_Anuncio ?? ''),
      request_ts: String(input.requested_at ?? input.request_ts ?? nowIso),
      requested_at: String(input.requested_at ?? input.request_ts ?? nowIso),
      today_tz: String(input.today_tz ?? ''),
      timezone: String(input.timezone ?? 'America/Argentina/Buenos_Aires'),
      dry_run: Boolean(input.dry_run ?? false),
      confirm: Boolean(input.confirm ?? false),
      confirm_token: String(input.confirm_token ?? ''),
      max_batch_size: Number(input.max_batch_size ?? input.batch_limit ?? 20),
      batch_limit: Number(input.batch_limit ?? input.max_batch_size ?? 20)
    },
    dispatched_at: nowIso
  }
}];

const source = $json ?? {};
return [{
  json: {
    event: 'internal_chain_dispatch_ok',
    source_workflow: 'contract-ui-management',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    correlation_id: String(source.correlation_id ?? ''),
    logical_execution_id: String(source.logical_execution_id ?? ''),
    status: 'dispatched',
    timestamp: new Date().toISOString()
  }
}];

const source = $json ?? {};
return [{
  json: {
    event: 'internal_chain_dispatch_error',
    source_workflow: 'contract-ui-management',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    correlation_id: String(source.correlation_id ?? ''),
    logical_execution_id: String(source.logical_execution_id ?? ''),
    status: 'error',
    error: String(source.error?.message ?? source.message ?? 'unknown_execute_workflow_error'),
    timestamp: new Date().toISOString()
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const idContrato = String(req.Contrato_ID).trim();
const actor = String(req.actor ?? 'ops@adskiller');
const reason = String(req.reason ?? 'Cierre manual por operacion').trim();
const found = items.find((i) => String(i.json.Contrato_ID ?? '').trim() === idContrato);
if (!found) { const err = new Error('Contrato no encontrado para baja_manual'); err.name = 'NotFoundError'; err.details = { Contrato_ID: idContrato }; throw err; }
return [{ json: { ...found.json, Contrato_ID: idContrato, Status_Contrato: 'Finalizado', Fecha_Finalizacion: req.request_ts, Updated_At: req.request_ts, Finalizado_By: actor, Finalizado_Reason: reason } }];

const req = $items('Validate Input', 0, 0)[0].json;
const idContrato = String(req.Contrato_ID).trim();
const ads = items.filter((i) => String(i.json.Contrato_ID ?? '').trim() === idContrato).map((i) => ({ ad_id: String(i.json.Ad_ID ?? ''), ad_name: String(i.json.Ad_Name ?? ''), ad_status: String(i.json.Status_Ad ?? i.json.Ad_Status ?? 'UNKNOWN').toUpperCase(), contract_status: String(i.json.Status_Contrato ?? '') })).filter((it) => it.ad_id);
return [{ json: { contract_id: idContrato, total: ads.length, items: ads } }];

const req = $items('Validate Input', 0, 0)[0].json;
const nowIso = new Date().toISOString();
const trackingId = String(req.tracking_id ?? `trk-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`);
const normalizedAction = String(req.action || '').trim();
const dispatchAction = normalizedAction === 'pause_active_preview' ? 'pause_active' : normalizedAction;
const maxBatchSize = Number(req.max_batch_size ?? req.batch_limit ?? 0);
const contractId = String(req.Contrato_ID ?? '');
const adId = String(req.Ad_ID ?? '');
const metaPatch = { method: 'PATCH', path: `/v23.0/${adId}`, body: { status: 'PAUSED' }, version: 'v1' };

return [{
  json: {
    tracking_id: trackingId,
    correlation_id: String(req.correlation_id),
    logical_execution_id: `${trackingId}:f1:${dispatchAction}`,
    action: dispatchAction,
    run_mode: 'manual',
    actor: String(req.actor ?? 'ops@adskiller'),
    requested_at: req.request_ts ?? nowIso,
    execution_id: String($execution?.id ?? ''),
    status: 'accepted',
    Contrato_ID: contractId,
    Ad_ID: adId,
    target_contract_id: contractId,
    target_ad_id: adId,
    precheck_status: 'UNKNOWN',
    meta_http_status: null,
    dry_run: Boolean(req.dry_run ?? false),
    confirm: Boolean(req.confirm ?? false),
    confirm_token: String(req.confirm_token ?? ''),
    max_batch_size: Number.isInteger(maxBatchSize) ? maxBatchSize : 0,
    batch_limit: Number.isInteger(maxBatchSize) ? maxBatchSize : Number(req.batch_limit ?? 0),
    reason: String(req.reason ?? ''),
    timezone: String(req.timezone ?? 'America/Argentina/Buenos_Aires'),
    meta_patch_method: metaPatch.method,
    meta_patch_path: metaPatch.path,
    meta_patch_body: JSON.stringify(metaPatch.body),
    meta_patch_version: metaPatch.version
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const page = Number(req.page ?? 1);
const pageSize = Number(req.page_size ?? 25);
const from = String(req.from ?? '').trim();
const to = String(req.to ?? '').trim();
const resultFilter = String(req.result ?? '').trim().toLowerCase();
const runModeFilter = String(req.run_mode ?? '').trim().toLowerCase();
const executionFilter = String(req.execution_id ?? '').trim();
const correlationFilter = String(req.correlation_id_filter ?? req.correlation_id_query ?? '').trim();
const trackingFilter = String(req.tracking_id ?? '').trim();
const parseTs = (v) => { const d = new Date(v); return Number.isNaN(d.getTime()) ? null : d; };
const fromDate = from ? parseTs(from) : null;
const toDate = to ? parseTs(to) : null;
let rows = items.map((i) => i.json || {});
rows = rows.filter((row) => {
  const ts = parseTs(row.requested_at ?? row.updated_at ?? row.timestamp ?? row.executed_at ?? '');
  if (fromDate && (!ts || ts < fromDate)) return false;
  if (toDate && (!ts || ts > toDate)) return false;
  if (resultFilter && String(row.status ?? row.result ?? '').toLowerCase() !== resultFilter) return false;
  if (runModeFilter && String(row.run_mode ?? '').toLowerCase() !== runModeFilter) return false;
  if (executionFilter && String(row.execution_id ?? '') !== executionFilter) return false;
  if (correlationFilter && String(row.correlation_id ?? '') !== correlationFilter) return false;
  if (trackingFilter && String(row.tracking_id ?? '') !== trackingFilter) return false;
  return true;
});
rows.sort((a, b) => String(b.updated_at ?? b.requested_at ?? b.timestamp ?? '').localeCompare(String(a.updated_at ?? a.requested_at ?? a.timestamp ?? '')));
const total = rows.length;
const start = (page - 1) * pageSize;
const paged = rows.slice(start, start + pageSize).map((row) => ({
  execution_id: String(row.execution_id ?? ''),
  tracking_id: String(row.tracking_id ?? ''),
  correlation_id: String(row.correlation_id ?? ''),
  action: String(row.action ?? ''),
  run_mode: String(row.run_mode ?? ''),
  result: String(row.final_status ?? row.status ?? row.result ?? ''),
  actor: String(row.actor ?? ''),
  contract_id: String(row.Contrato_ID ?? row.contract_id ?? ''),
  ad_id: String(row.Ad_ID ?? row.ad_id ?? ''),
  precheck_status: String(row.precheck_status ?? row.ad_status_meta ?? 'UNKNOWN'),
  meta_http_status: Number(row.meta_http_status ?? row.pause_status_code ?? row.precheck_status_code ?? 0) || null,
  pause_attempt: Number(row.pause_attempt ?? row.precheck_attempt ?? 0) || 0,
  pause_max_attempts: Number(row.pause_max_attempts ?? row.precheck_max_attempts ?? 0) || 0,
  reason: String(row.pause_reason ?? row.precheck_reason ?? row.error ?? ''),
  timestamps: {
    requested_at: String(row.requested_at ?? row.timestamp ?? ''),
    updated_at: String(row.updated_at ?? row.timestamp ?? row.requested_at ?? ''),
    executed_at: String(row.executed_at ?? row.updated_at ?? row.timestamp ?? row.requested_at ?? '')
  },
  executed_at: String(row.executed_at ?? row.updated_at ?? row.timestamp ?? row.requested_at ?? '')
}));
return [{ json: { total, page, page_size: pageSize, not_found: Boolean(trackingFilter) && total === 0, items: paged } }];

const req = $items('Validate Input', 0, 0)[0].json;
const contractId = String(req.Contrato_ID ?? '').trim();
const maxBatchSize = Number(req.max_batch_size ?? req.batch_limit ?? 20);
const actor = String(req.actor ?? 'ops@adskiller').trim();
const ttlMs = 10 * 60 * 1000;

function encodeBase64Url(value) {
  return Buffer.from(value, 'utf8')
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

const candidates = items
  .filter((i) => String(i.json.Contrato_ID ?? '').trim() === contractId)
  .filter((i) => String(i.json.Status_Contrato ?? '').trim().toLowerCase() === 'activo')
  .slice(0, maxBatchSize)
  .map((i) => ({
    ad_id: String(i.json.Ad_ID ?? ''),
    ad_name: String(i.json.Ad_Name ?? ''),
    contract_id: contractId
  }));

const nowMs = Date.now();
const expiresAt = nowMs + ttlMs;
const tokenPayload = {
  contract_id: contractId,
  actor,
  max_batch_size: maxBatchSize,
  issued_at_epoch_ms: nowMs,
  expires_at_epoch_ms: expiresAt,
  candidate_count: candidates.filter((x) => x.ad_id).length
};
const confirmToken = encodeBase64Url(JSON.stringify(tokenPayload));

return [{
  json: {
    dry_run: true,
    contract_id: contractId,
    max_batch_size: maxBatchSize,
    total_candidates: candidates.length,
    would_pause: candidates.filter((x) => x.ad_id).length,
    confirm_token: confirmToken,
    confirm_token_expires_at: new Date(expiresAt).toISOString(),
    items: candidates
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const query = String(req.q ?? '').trim();
if (!query) {
  throw new Error('q es obligatorio para influencers_search');
}
const limitValue = Number(req.limit ?? 10);
const limit = Math.min(20, Math.max(1, limitValue));
if (!Number.isInteger(limitValue) || limitValue < 1 || limitValue > 20) {
  throw new Error('limit debe ser un entero positivo entre 1 y 20');
}

function normalize(value) {
  return String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, ' ').trim();
}

function tokens(value) {
  return normalize(value).split(' ').filter(Boolean);
}

function overlapScore(left, right) {
  if (!left.length || !right.length) return 0;
  const set = new Set(right);
  let hits = 0;
  for (const token of left) {
    if (set.has(token)) hits += 1;
  }
  return hits / Math.max(left.length, right.length);
}

const queryNorm = normalize(query);
const queryTokens = tokens(query);
const bestByKey = new Map();

for (const item of items) {
  const row = item.json ?? {};
  const name = String(row.Cliente ?? row.influencer_name ?? row.name ?? row.Ad_Name ?? '').trim();
  if (!name) continue;

  const channel = String(row.channel ?? row.Channel ?? row.Canal ?? row.notification_channel ?? '').trim();
  const nameNorm = normalize(name);
  const channelNorm = normalize(channel);
  const adNorm = normalize(row.Ad_Name ?? row.Regex_Anuncio ?? '');

  let score = 0;
  if (nameNorm === queryNorm) {
    score = 1;
  } else if (queryNorm && nameNorm.includes(queryNorm)) {
    score = 0.92;
  } else if (nameNorm && queryNorm.includes(nameNorm)) {
    score = 0.84;
  } else {
    score = Math.max(
      overlapScore(queryTokens, tokens(name)),
      overlapScore(queryTokens, tokens(channelNorm)),
      overlapScore(queryTokens, tokens(adNorm))
    );
  }

  if (channelNorm) {
    if (channelNorm === queryNorm) {
      score = Math.max(score, 0.95);
    } else if (queryNorm && (channelNorm.includes(queryNorm) || queryNorm.includes(channelNorm))) {
      score = Math.max(score, Math.min(1, score + 0.1));
    }
  }

  if (adNorm && queryNorm && (adNorm.includes(queryNorm) || queryNorm.includes(adNorm))) {
    score = Math.max(score, Math.min(1, score + 0.05));
  }

  if (score <= 0) continue;
  const key = `${nameNorm}|${channelNorm}`;
  const current = bestByKey.get(key);
  if (!current || score > current.score) {
    bestByKey.set(key, { name, channel, score });
  }
}

const ranked = [...bestByKey.values()].sort((a, b) => b.score - a.score || a.name.localeCompare(b.name) || a.channel.localeCompare(b.channel));
const total = ranked.length;
const itemsOut = ranked.slice(0, limit).map((row) => ({ name: row.name, channel: row.channel, score: Number(row.score.toFixed(2)) }));

return [{ json: { ok: true, action: 'influencers_search', query, limit, total, items: itemsOut } }];

const req = $items('Validate Input', 0, 0)[0].json;
const trackingId = String(req.tracking_id ?? '').trim();

const rows = items
  .map((i) => i.json || {})
  .filter((row) => String(row.tracking_id ?? '').trim() === trackingId);

if (!rows.length) {
  return [{
    json: {
      tracking_id: trackingId,
      status: 'not_found',
      not_found: true,
      result: null,
      transitions: [],
      timestamps: { requested_at: null, updated_at: null },
      last_update_at: null
    }
  }];
}

rows.sort((a, b) => String(a.updated_at ?? a.requested_at ?? a.timestamp ?? a.executed_at ?? '').localeCompare(String(b.updated_at ?? b.requested_at ?? b.timestamp ?? b.executed_at ?? '')));
const latest = rows[rows.length - 1];
const rawStatus = String(latest.final_status ?? latest.status ?? latest.result ?? '').trim().toLowerCase();
const normalizedStatus = (() => {
  if (['paused', 'failed', 'already_paused', 'not_found'].includes(rawStatus)) return rawStatus;
  if (['accepted', 'queued', 'pending'].includes(rawStatus)) return 'queued';
  if (['processing', 'running', 'in_progress', 'dispatched'].includes(rawStatus)) return 'processing';
  return rawStatus || 'processing';
})();

const transitions = rows.map((row) => ({
  status: String(row.final_status ?? row.status ?? row.result ?? '').trim().toLowerCase() || 'unknown',
  at: String(row.updated_at ?? row.requested_at ?? row.timestamp ?? row.executed_at ?? ''),
  source: String(row.source_workflow ?? row.source ?? ''),
  meta_http_status: Number(row.meta_http_status ?? row.pause_status_code ?? row.precheck_status_code ?? 0) || null,
  attempt: Number(row.pause_attempt ?? row.precheck_attempt ?? 0) || 0
}));

return [{
  json: {
    tracking_id: trackingId,
    not_found: false,
    correlation_id: String(latest.correlation_id ?? ''),
    contract_id: String(latest.Contrato_ID ?? latest.contract_id ?? ''),
    ad_id: String(latest.Ad_ID ?? latest.ad_id ?? ''),
    status: normalizedStatus,
    result: {
      precheck_status: String(latest.precheck_status ?? latest.ad_status_meta ?? 'UNKNOWN'),
      meta_http_status: Number(latest.meta_http_status ?? latest.pause_status_code ?? latest.precheck_status_code ?? 0) || null,
      pause_attempt: Number(latest.pause_attempt ?? 0) || 0,
      pause_max_attempts: Number(latest.pause_max_attempts ?? 0) || 0,
      reason: String(latest.pause_reason ?? latest.precheck_reason ?? '')
    },
    timestamps: {
      requested_at: String(latest.requested_at ?? latest.timestamp ?? ''),
      updated_at: String(latest.updated_at ?? latest.timestamp ?? latest.requested_at ?? '')
    },
    transitions,
    last_update_at: String(latest.updated_at ?? latest.timestamp ?? latest.requested_at ?? '')
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const page = Number(req.page ?? 1);
const pageSize = Number(req.page_size ?? 25);
const from = String(req.from ?? '').trim();
const to = String(req.to ?? '').trim();
const severityFilter = String(req.severity ?? '').trim().toUpperCase();
const statusFilter = String(req.status ?? '').trim().toLowerCase();

const parseTs = (value) => {
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const fromDate = from ? parseTs(from) : null;
const toDate = to ? parseTs(to) : null;

let rows = items.map((item) => item.json || {});

rows = rows.filter((row) => {
  const createdAtRaw = String(row.Creada_At ?? row.created_at ?? row.timestamp ?? '').trim();
  const createdAt = parseTs(createdAtRaw);
  const severity = String(row.Severidad ?? row.severity ?? '').trim().toUpperCase();
  const status = String(row.Estado ?? row.status ?? '').trim().toLowerCase();

  if (fromDate && (!createdAt || createdAt < fromDate)) return false;
  if (toDate && (!createdAt || createdAt > toDate)) return false;
  if (severityFilter && severity !== severityFilter) return false;
  if (statusFilter && status !== statusFilter) return false;

  return true;
});

rows.sort((a, b) => String(b.Creada_At ?? b.created_at ?? '').localeCompare(String(a.Creada_At ?? a.created_at ?? '')));

const total = rows.length;
const start = (page - 1) * pageSize;

const paged = rows.slice(start, start + pageSize).map((row) => ({
  alert_id: String(row.Alerta_ID ?? row.alert_id ?? ''),
  severity: String(row.Severidad ?? row.severity ?? '').toUpperCase(),
  message: String(row.Motivo ?? row.message ?? ''),
  status: String(row.Estado ?? row.status ?? ''),
  created_at: String(row.Creada_At ?? row.created_at ?? ''),
  contract_id: String(row.Contrato_ID ?? row.contract_id ?? ''),
  ad_id: String(row.Ad_ID ?? row.ad_id ?? ''),
  correlation_id: String(row.Correlation_ID ?? row.correlation_id ?? ''),
  execution_id: String(row.execution_id ?? row.Execution_ID ?? '')
}));

return [{
  json: {
    total,
    page,
    page_size: pageSize,
    items: paged
  }
}];
